import type { StageInput, StageOutput, StageRuntime } from '../contracts.js';

export async function runStage(input: StageInput, runtime: StageRuntime): Promise<StageOutput> {
  const facts = parseFacts(input.domain['inputs.initial_user_text']);
  const plan = String(facts.plan);
  const seats = Number(facts.seats);
  const region = String(facts.region);
  const pricing = plan === 'enterprise'
    ? { base_usd: 500, seat_rate_usd: 12 }
    : plan === 'pro'
      ? { base_usd: 100, seat_rate_usd: 7 }
      : { base_usd: 40, seat_rate_usd: 5 };
  const regionMultiplier = region === 'eu' ? 1.2 : region === 'apac' ? 1.1 : 1;
  const subtotal = pricing.base_usd + seats * pricing.seat_rate_usd;
  const total = Math.round(subtotal * regionMultiplier);
  return {
    result_json: JSON.stringify({
      stage: input.stage,
      plan,
      seats,
      region,
      base_usd: pricing.base_usd,
      seat_rate_usd: pricing.seat_rate_usd,
      subtotal_usd: subtotal,
      region_multiplier: regionMultiplier,
      total_usd: total,
      currency: 'USD',
      priced_at: runtime.now(),
    }),
    items_json: JSON.stringify(['plan:' + plan, 'seats:' + seats, 'total_usd:' + total]),
    digest: '',
  };
}

function parseFacts(value: unknown): Record<string, unknown> {
  if (typeof value !== 'string') return {};
  try {
    const parsed = JSON.parse(value) as unknown;
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed as Record<string, unknown> : {};
  } catch {
    return {};
  }
}
